#include <stdio.h>
#include <stdlib.h>

void backtrack(int start, int combinationCount, int targetSum, int *current, int index, int **result, int *resultSize) {
    if (index == combinationCount) {
        if (targetSum == 0) {
            result[*resultSize] = (int *)malloc(combinationCount * sizeof(int));
            for (int i = 0; i < combinationCount; i++) {
                result[*resultSize][i] = current[i];
            }
            (*resultSize)++;
        }
        return;
    }

    for (int i = start; i <= 9; i++) {
        if (i > targetSum) break;
        current[index] = i;
        backtrack(i + 1, combinationCount, targetSum - i, current, index + 1, result, resultSize);
    }
}

void findCombinations(int combinationCount, int targetSum) {
    int *current = (int *)malloc(combinationCount * sizeof(int));
    int **result = (int **)malloc(1000 * sizeof(int *));
    int resultSize = 0;
    backtrack(1, combinationCount, targetSum, current, 0, result, &resultSize);
    for (int i = 0; i < resultSize; i++) {
        for (int j = 0; j < combinationCount; j++) {
            printf("%d ", result[i][j]);
        }
        printf("\n");
    }
    free(current);
    for (int i = 0; i < resultSize; i++) {
        free(result[i]);
    }
    free(result);
}

int main() {
    int T;
    scanf("%d", &T);
    while (T--) {
        int combinationCount, targetSum;
        scanf("%d %d", &combinationCount, &targetSum);
        findCombinations(combinationCount, targetSum);
    }
    return 0;
}

