void backtrack(int start, int combinationCount, int targetSum, vector<int> &current, vector<vector<int>> &result) {
    if (current.size() == combinationCount) {
        if (targetSum == 0) {
            result.push_back(current);
        }
        return;
    }

    for (int i = start; i <= 9; i++) {
        if (i > targetSum) break;
        current.push_back(i);
        backtrack(i + 1, combinationCount, targetSum - i, current, result);
        current.pop_back();
    }
}

vector<vector<int>> findCombinations(int combinationCount, int targetSum) {
    vector<vector<int>> result;
    vector<int> current;
    backtrack(1, combinationCount, targetSum, current, result);
    return result;
}

int main() {
    ios::sync_with_stdio(false);
    cin.tie(NULL);
    int T;
    cin >> T;
    while (T--) {
        int combinationCount, targetSum;
        cin >> combinationCount >> targetSum;
        vector<vector<int>> result = findCombinations(combinationCount, targetSum);
        for (auto &combination : result) {
            for (int num : combination) {
                cout << num << " ";
            }
            cout << endl;
        }
    }
    return 0;
