import java.util.ArrayList;
import java.util.List;
import java.util.Scanner;

public class Main {
    public static void backtrack(int start, int combinationCount, int targetSum, List<Integer> current, List<List<Integer>> result) {
        if (current.size() == combinationCount) {
            if (targetSum == 0) {
                result.add(new ArrayList<>(current));
            }
            return;
        }

        for (int i = start; i <= 9; i++) {
            if (i > targetSum) break;
            current.add(i);
            backtrack(i + 1, combinationCount, targetSum - i, current, result);
            current.remove(current.size() - 1);
        }
    }

    public static List<List<Integer>> findCombinations(int combinationCount, int targetSum) {
        List<List<Integer>> result = new ArrayList<>();
        List<Integer> current = new ArrayList<>();
        backtrack(1, combinationCount, targetSum, current, result);
        return result;
    }

    public static void main(String[] args) {
        Scanner scanner = new Scanner(System.in);
        int T = scanner.nextInt();
        while (T-- > 0) {
            int combinationCount = scanner.nextInt();
            int targetSum = scanner.nextInt();
            List<List<Integer>> result = findCombinations(combinationCount, targetSum);
            for (List<Integer> combination : result) {
                for (int num : combination) {
                    System.out.print(num + " ");
                }
                System.out.println();
            }
        }
    }
}

